import{_ as a,o as d,c as t,a2 as s}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Конфигурация","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/configuration.md","filePath":"ru/guide/configuration.md"}'),i={name:"ru/guide/configuration.md"};function o(c,e,n,r,l,p){return d(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="конфигурация" tabindex="-1">Конфигурация <a class="header-anchor" href="#конфигурация" aria-label="Permalink to &quot;Конфигурация&quot;">​</a></h1><p>Clearance поставляется с разумными значениями по умолчанию, поэтому он работает &quot;из коробки&quot; после <a href="/clearance-docs/ru/guide/installation.html">установки</a>. Опубликуйте файл конфигурации, когда вам нужно настроить префикс маршрута, middleware, контекстные модели или любую другую настройку.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Это публикует <code>config/clearance.php</code>.</p><h2 id="справочник-конфигурации" tabindex="-1">Справочник конфигурации <a class="header-anchor" href="#справочник-конфигурации" aria-label="Permalink to &quot;Справочник конфигурации&quot;">​</a></h2><p>Это исчерпывающий справочник по каждому ключу в <code>config/clearance.php</code>. Другие страницы этой документации ссылаются сюда вместо повторения таблицы.</p><table tabindex="0"><thead><tr><th>Ключ</th><th>По умолчанию</th><th>Назначение</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>Префикс URI для всех маршрутов панели.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>Применяется ко всем маршрутам панели перед <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>Разрешение, проверяемое middleware доступа.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>По умолчанию <code>auth.providers.users.model</code>.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Главный переключатель модуля пользователей (маршруты + компоненты Livewire).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - модели, которые могут выступать контекстами для привязки ролей.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>Принудительное соблюдение именования разрешений <code>group-action</code>.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>Символ-разделитель - только <code>&#39;-&#39;</code> или <code>&#39;_&#39;</code>.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>Переопределить автоматически определённые guard&#39;ы из <code>config/auth.php</code>. Пусто = автоопределение всех.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>Драйверы, принимаемые при внедрении guard&#39;ов из БД в <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>Blade-layout для полностраничных компонентов. <code>null</code> = layout по умолчанию основного приложения (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>Автоматически назначать настроенную в Настройках роль по умолчанию при событии <code>Registered</code>.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>Опционально: <code>super_admin</code> обходит все проверки Gate во всём приложении.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = автоопределение через <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="соглашение-об-именовании-разрешении" tabindex="-1">Соглашение об именовании разрешений <a class="header-anchor" href="#соглашение-об-именовании-разрешении" aria-label="Permalink to &quot;Соглашение об именовании разрешений&quot;">​</a></h2><p>Разрешения должны следовать формату <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Отключите принудительное соблюдение для конкретного окружения с помощью <code>enforce_naming_convention</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Разделитель проверяется при загрузке</p><p>Значение <code>naming_separator</code> - единственная часть этой конфигурации, которая попадает в сырой фрагмент SQL (группировка/сортировка разрешений), поэтому допускаются только <code>-</code> или <code>_</code>.</p></div><h2 id="настроика-middleware" tabindex="-1">Настройка middleware <a class="header-anchor" href="#настроика-middleware" aria-label="Permalink to &quot;Настройка middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Имена маршрутов остаются стабильными независимо от изменений префикса или middleware - см. <a href="/clearance-docs/ru/guide/quick-start.html">Быстрый старт</a> для полной таблицы маршрутов.</p><h2 id="смотрите-также" tabindex="-1">Смотрите также <a class="header-anchor" href="#смотрите-также" aria-label="Permalink to &quot;Смотрите также&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/guide/quick-start.html">Быстрый старт</a> - подключение панели с применёнными этими настройками</li><li><a href="/clearance-docs/ru/guide/publishing.html">Публикация ресурсов</a> - публикация переводов и объяснение ключа <code>layout</code></li><li><a href="/clearance-docs/ru/features/guards.html">Guards</a> - как используются <code>guards</code> и <code>allowed_guard_drivers</code></li><li><a href="/clearance-docs/ru/features/super-admin.html">Super Admin</a> - как работает <code>super_admin_gate_bypass</code></li></ul>`,18)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
